def normalize_match_text(value: str) -> str:
    return re.sub(r"[\W_]+", "", value.lower(), flags=re.UNICODE)


def item_matches_query(item: dict[str, Any], query: str) -> bool:
    haystacks = [
        item.get("text", ""),
        item.get("note", ""),
        item.get("id", ""),
    ]

    if any(query in haystack.lower() for haystack in haystacks):
        return True

    normalized_query = normalize_match_text(query)
    if not normalized_query:
        return False

    query_chars = set(normalized_query)
    for haystack in haystacks:
        normalized_haystack = normalize_match_text(haystack)
        if not normalized_haystack:
            continue
        if normalized_query in normalized_haystack:
            return True

        overlap_ratio = len(query_chars & set(normalized_haystack)) / len(query_chars)
        if overlap_ratio >= 0.6:
            return True

    return False


