def format_timestamp(timestamp: str) -> str:
    try:
        return datetime.fromisoformat(timestamp).astimezone().strftime("%Y-%m-%d %H:%M")
    except ValueError:
        return timestamp


def parse_timestamp(timestamp: str) -> datetime:
    try:
        return datetime.fromisoformat(timestamp)
    except ValueError:
        return datetime.min.replace(tzinfo=timezone.utc)


def sort_items(items: list[dict[str, Any]]) -> list[dict[str, Any]]:
    return sorted(
        items,
        key=lambda item: parse_timestamp(item.get("updated_at") or item.get("created_at", "")),
        reverse=True,
    )


def print_json(payload: Any) -> None:
    print(json.dumps(payload, ensure_ascii=False, indent=2))


def render_item(item: dict[str, Any]) -> str:
    created_at = format_timestamp(item.get("created_at", ""))
    line = f"- [{item['id']} | {created_at}] {item['text']}"
    note = item.get("note", "").strip()
    if note:
        line += f"（{LABEL_NOTE}：{note}）"
    thread_label = short_thread_label(item.get("source_thread_id", UNKNOWN_THREAD))
    return line + f"\n  {LABEL_FIRST_THREAD}：{thread_label}"


def render_section(title: str, items: list[dict[str, Any]]) -> str:
    lines = [title]
    if not items:
        lines.append(f"- {LABEL_NONE}")
        return "\n".join(lines)
    lines.extend(render_item(item) for item in sort_items(items))
    return "\n".join(lines)


def render_focus(query: str, items: list[dict[str, Any]], status: str) -> str:
    status_label = LABEL_COMPLETED if status == "completed" else LABEL_PENDING
    header = f"\u548c\u201c{query}\u201d\u6709\u5173\u7684{status_label}\u9700\u6c42\uff1a"
    if not items:
        return header + f"\n- {LABEL_NONE}"
    lines = [header]
    lines.extend(render_item(item) for item in sort_items(items))
    return "\n".join(lines)


